-- CP4 catalog seed (part 2 of 2) — load 298 deduped/enriched catalog cookbooks as is_catalog=true.
--
-- Net-new + idempotent: inserts only titles not already in `books` (by isbn13, or by
-- normalized title+author for blank-isbn rows). Re-running is a no-op. Existing owned/
-- workstream rows are untouched (they stay is_catalog=false). Catalog updates = new migration.
--
-- cover_image_url holds the Open Library URL (hotlinked; the cover-host pass rehosts later).
-- verification_source='catalog_seed' (the CHECK is extended below to permit it).

-- 1. Permit verification_source='catalog_seed' (extend the existing CHECK; additive).
ALTER TABLE "public"."books" DROP CONSTRAINT IF EXISTS "books_verification_source_check";
ALTER TABLE "public"."books" ADD CONSTRAINT "books_verification_source_check"
  CHECK (("verification_source" = ANY (ARRAY['isbn_api'::"text", 'manual_review'::"text", 'user_submitted'::"text", 'catalog_seed'::"text"])));

-- 2. Idempotent net-new insert of the 298 catalog titles.
INSERT INTO "public"."books"
  (title, author, isbn, isbn13, cover_image_url, publication_year, is_catalog, is_verified, verification_source, toc_extracted_at)
SELECT v.title, v.author, NULL::text, NULLIF(v.isbn13,''), NULLIF(v.cover_image_url,''),
       NULLIF(v.publication_year,'')::int, true, false, 'catalog_seed', NULL::timestamptz
